const raw = $input.first().json;
const p = (raw.body && typeof raw.body === 'object' && !Array.isArray(raw.body)) ? raw.body : raw;

if (!p.endpoint || !p.method || !p.headers) {
  throw new Error('Payload invalido: endpoint, method e headers sao obrigatorios');
}

const baseUrl = 'http://177.38.10.218:8082/datasnap/rest/TSMApi';
const url = `${baseUrl}/"${p.endpoint}"`;

try {
  const response = await this.helpers.httpRequest({
    url,
    method: p.method,
    headers: p.headers,
    body: p.body,
    json: false,
    returnFullResponse: true,
    simple: false,
    timeout: 30000,
  });

  let body = response.body;
  if (typeof body === 'string' && body.trim()) {
    try { body = JSON.parse(body); } catch {}
  }

  return [{
    json: {
      status: response.statusCode || 200,
      body: body ?? null,
    },
  }];
} catch (err) {
  const response = err?.response || null;
  let body = response?.body ?? err?.body ?? null;

  if (typeof body === 'string' && body.trim()) {
    try { body = JSON.parse(body); } catch {}
  }

  return [{
    json: {
      status: response?.statusCode || err?.statusCode || 500,
      body: body ?? null,
      error: err?.message || 'Erro ao conectar no Proxis',
    },
  }];
}
